external_knowledge:
Recent login: within the last 30 days;
Active regions: regions with a status of 'active';
Performance metrics period: January 1, 2022, to December 31, 2022.

sql:
SELECT user_id
FROM configuration_logs
WHERE region_id = 2;

SELECT AVG(metric_value) AS average_read_latency
FROM system_performance
WHERE region_id = 1 AND metric_name = 'read_latency';

SELECT u.user_name, u.email, u.role, ur.permissions
FROM users u
JOIN user_roles ur ON u.role = ur.role_name;

SELECT * 
FROM memory_types
WHERE executable = 0 AND cacheable = 0;

SELECT type_name, cacheable 
FROM memory_types 
WHERE memory_type_id = 1;

SELECT MAX(metric_value)
FROM system_performance
WHERE metric_name = 'write_latency';

SELECT performance_id
FROM system_performance
WHERE metric_name = 'read_latency' AND metric_value > (SELECT AVG(metric_value) FROM system_performance WHERE metric_name = 'read_latency');
